"""
Conversation State Tracking for Gradual Resource Allocation

Tracks conversation depth and ensures resources gradually increase,
never decrease, as conversations progress and become more complex.
"""

from dataclasses import dataclass
from typing import Optional


@dataclass
class ConversationState:
    """
    Tracks conversation progression and minimum resource requirements.

    Ensures resources only increase as:
    - Conversation turns accumulate
    - Tools are used repeatedly
    - Peak complexity increases

    Prevents resource thrashing where resources drop mid-conversation.
    """

    def __init__(self):
        """Initialize conversation state tracking"""
        self.turn_count: int = 0
        self.tool_calls_made: int = 0
        self.peak_complexity: float = 0.0
        self.minimum_resources: int = 25  # Start at minimum (MINIMAL profile)
        self.last_complexity: float = 0.0

    def update_for_turn(self, complexity_score: float, used_tools: bool = False,
                       tool_count: int = 0) -> None:
        """
        Update conversation state after each turn.

        Args:
            complexity_score: Current turn's complexity (0.0-1.0)
            used_tools: Whether tools were used this turn
            tool_count: Number of tools called this turn
        """
        self.turn_count += 1
        if used_tools:
            self.tool_calls_made += max(1, tool_count)

        # Track peak complexity seen
        self.peak_complexity = max(self.peak_complexity, complexity_score)
        self.last_complexity = complexity_score

        # Gradual floor increase based on conversation depth
        # Turn-based progression
        if self.turn_count >= 3:
            self.minimum_resources = max(self.minimum_resources, 35)
        if self.turn_count >= 5:
            self.minimum_resources = max(self.minimum_resources, 40)
        if self.turn_count >= 8:
            self.minimum_resources = max(self.minimum_resources, 45)
        if self.turn_count >= 12:
            self.minimum_resources = max(self.minimum_resources, 50)
        if self.turn_count >= 20:
            self.minimum_resources = max(self.minimum_resources, 55)

        # Tool usage increases floor
        if self.tool_calls_made >= 1:
            self.minimum_resources = max(self.minimum_resources, 40)
        if self.tool_calls_made >= 3:
            self.minimum_resources = max(self.minimum_resources, 50)
        if self.tool_calls_made >= 5:
            self.minimum_resources = max(self.minimum_resources, 55)
        if self.tool_calls_made >= 8:
            self.minimum_resources = max(self.minimum_resources, 60)
        if self.tool_calls_made >= 12:
            self.minimum_resources = max(self.minimum_resources, 65)

        # Peak complexity floor (never drop below what we've needed)
        if self.peak_complexity >= 0.3:
            self.minimum_resources = max(self.minimum_resources, 40)
        if self.peak_complexity >= 0.5:
            self.minimum_resources = max(self.minimum_resources, 50)
        if self.peak_complexity >= 0.7:
            self.minimum_resources = max(self.minimum_resources, 60)
        if self.peak_complexity >= 0.85:
            self.minimum_resources = max(self.minimum_resources, 70)

    def get_minimum_resources(self) -> int:
        """
        Get the minimum resource percentage for current conversation state.

        Returns:
            Minimum resource percentage (25-75)
        """
        return min(75, self.minimum_resources)  # Cap at 75%

    def get_context_aware_minimum(self, context_word_count: int) -> int:
        """
        Get minimum resources considering both state and context length.

        Args:
            context_word_count: Number of words in conversation context

        Returns:
            Minimum resource percentage
        """
        base_minimum = self.get_minimum_resources()

        # Context length bonus
        if context_word_count > 1000:
            context_minimum = 65
        elif context_word_count > 600:
            context_minimum = 60
        elif context_word_count > 400:
            context_minimum = 50
        elif context_word_count > 200:
            context_minimum = 45
        elif context_word_count > 100:
            context_minimum = 35
        else:
            context_minimum = 25

        return max(base_minimum, context_minimum)

    def reset(self) -> None:
        """Reset conversation state (for new sessions)"""
        self.__init__()

    def get_stats(self) -> dict:
        """Get conversation state statistics for debugging"""
        return {
            'turn_count': self.turn_count,
            'tool_calls_made': self.tool_calls_made,
            'peak_complexity': self.peak_complexity,
            'last_complexity': self.last_complexity,
            'minimum_resources': self.minimum_resources,
        }
